import jwt  # pip install PyJWT
from datetime import datetime, timedelta

JWT_SECRET = 'your-secret-key'  # use env variable in production
JWT_ALGORITHM = 'HS256'
JWT_EXPIRY_HOURS = 24

def create_token(user_id: str, tier: str, roles: list[str]) -> str:
    payload = {
        'sub': user_id,
        'tier': tier,
        'roles': roles,
        'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRY_HOURS),
        'iat': datetime.utcnow(),
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)

def decode_token(token: str) -> dict:
    try:
        return jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail='Token expired')
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail='Invalid token')

async def require_jwt(authorization: str = Header(...)) -> dict:
    if not authorization.startswith('Bearer '):
        raise HTTPException(status_code=401, detail='Bearer token required')
    return decode_token(authorization[7:])

SYSTEM_PROMPTS: dict[str, str] = {
    'customer_support': (
        'You are a customer support assistant for AcmeCorp. '
        'You may only discuss AcmeCorp products and order status. '
        'Do not discuss competitors, pricing strategy, or internal processes.'
    ),
    'developer': (
        'You are a technical assistant for AcmeCorp developers. '
        'You may discuss code, APIs, and integration patterns.'
    ),
    'admin': (
        'You are an unrestricted internal assistant for AcmeCorp administrators.'
    ),
}

TOOL_ALLOWLISTS: dict[str, set[str]] = {
    'customer_support': {'lookup_order', 'submit_ticket'},
    'developer':        {'search_docs', 'run_code_snippet'},
    'admin':            {'lookup_order', 'submit_ticket', 'search_docs',
                         'run_code_snippet', 'view_audit_log', 'manage_users'},
}

def get_scoped_config(role: str) -> dict:
    if role not in SYSTEM_PROMPTS:
        raise HTTPException(status_code=403, detail=f'Unknown role: {role}')
    return {
        'system': SYSTEM_PROMPTS[role],
        'allowed_tools': TOOL_ALLOWLISTS.get(role, set()),
    }

# At request time:
def build_llm_request(principal: dict, user_message: str, requested_tools: list[str]) -> dict:
    role = principal.get('role', 'customer_support')
    config = get_scoped_config(role)

    # Intersect requested tools with role allowlist
    allowed = config['allowed_tools']
    approved_tools = [t for t in requested_tools if t in allowed]
    rejected = set(requested_tools) - allowed
    if rejected:
        raise HTTPException(
            status_code=403,
            detail=f'Tools not permitted for role {role!r}: {rejected}',
        )

    return {
        'system': config['system'],
        'tools': approved_tools,
        'messages': [{'role': 'user', 'content': user_message}],
    }

from datetime import datetime
import threading

class TokenBudgetTracker:
    def __init__(self):
        self._usage: dict[str, dict[str, int]] = {}
        self._lock = threading.Lock()

    def _month_key(self) -> str:
        now = datetime.utcnow()
        return f'{now.year}-{now.month:02d}'

    def record_usage(self, user_id: str, tokens_used: int) -> None:
        month = self._month_key()
        with self._lock:
            if user_id not in self._usage:
                self._usage[user_id] = {}
            self._usage[user_id][month] = (
                self._usage[user_id].get(month, 0) + tokens_used
            )

    def get_usage(self, user_id: str) -> int:
        month = self._month_key()
        with self._lock:
            return self._usage.get(user_id, {}).get(month, 0)

    def check_budget(self, user_id: str, policy: TierPolicy,
                     requested_tokens: int) -> None:
        used = self.get_usage(user_id)
        if used + requested_tokens > policy.tokens_per_month:
            raise HTTPException(
                status_code=429,
                detail=f'Monthly token budget exceeded. Used: {used}, Budget: {policy.tokens_per_month}',
            )

budget_tracker = TokenBudgetTracker()
