from dataclasses import dataclass

@dataclass
class TenantKey:
    key_id: str
    tenant_id: str
    scopes: set[str]      # e.g. {'read', 'write', 'admin'}
    model_override: str | None = None  # tenant-specific model
    rate_limit: int = 60  # req/min

def enforce_tenant_isolation(
    tenant_key: TenantKey,
    resource_tenant_id: str,
) -> None:
    if tenant_key.tenant_id != resource_tenant_id:
        raise HTTPException(
            status_code=403,
            detail='Cross-tenant access denied',
        )

# Namespaced vector store lookup — never cross tenant boundaries
def rag_search(query: str, tenant_id: str, top_k: int = 5) -> list[dict]:
    # Always filter by tenant_id in the vector DB query
    results = vector_db.search(
        query=query,
        filter={'tenant_id': tenant_id},  # mandatory filter
        top_k=top_k,
    )
    return results

def vector_db_search_stub(query, filter, top_k): return []
vector_db = type('DB', (), {'search': staticmethod(vector_db_search_stub)})()
